1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const BLOCK_SIZE = 3;
4	const BLOCK_BASE_PREMIUM = 60;
5	
6	// Main items are insured individually at their base premium.
7	const MAIN_ITEM_BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	};
13	
14	// Components are grouped by type; exactly BLOCK_SIZE alike components
15	// form a "block" with a fixed base premium instead of per-item pricing.
16	const COMPONENT_BASE_PREMIUMS: Record<string, number> = {
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const isComponent = (itemType: string): boolean =>
22	  itemType in COMPONENT_BASE_PREMIUMS;
23	
24	const isMainItem = (itemType: string): boolean =>
25	  itemType in MAIN_ITEM_BASE_PREMIUMS;
26	
27	const isKnownItemType = (itemType: string): boolean =>
28	  isMainItem(itemType) || isComponent(itemType);
29	
30	const countByType = (items: { type: string }[]): Record<string, number> =>
31	  items.reduce<Record<string, number>>((counts, item) => {
32	    counts[item.type] = (counts[item.type] ?? 0) + 1;
33	    return counts;
34	  }, {});
35	
36	const componentGroupPremium = (componentType: string, count: number): number => {
37	  const perItem = COMPONENT_BASE_PREMIUMS[componentType];
38	  return count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * perItem;
39	};
40	
41	const computeBasePremium = (items: { type: string }[]): number => {
42	  const counts = countByType(items);
43	  return Object.entries(counts).reduce((total, [type, count]) => {
44	    if (isComponent(type)) {
45	      return total + componentGroupPremium(type, count);
46	    }
47	    return total + count * (MAIN_ITEM_BASE_PREMIUMS[type] ?? 0);
48	  }, 0);
49	};
50	
51	const CURSED_SURCHARGE_RATE = 0.5;
52	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
53	const HIGH_ENCHANTMENT_THRESHOLD = 5;
54	
55	const computeItemSurcharges = (
56	  items: { type: string; cursed?: boolean; enchantment?: number }[],
57	): number =>
58	  items.reduce((total, item) => {
59	    if (!isMainItem(item.type)) {
60	      return total;
61	    }
62	    const base = MAIN_ITEM_BASE_PREMIUMS[item.type];
63	    let surcharge = 0;
64	    if (item.cursed) {
65	      surcharge += base * CURSED_SURCHARGE_RATE;
66	    }
67	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
68	      surcharge += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
69	    }
70	    return total + surcharge;
71	  }, 0);
72	
73	const LOYALTY_DISCOUNT_RATE = 0.2;
74	const LOYALTY_THRESHOLD_YEARS = 2;
75	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
76	
77	type PremiumContext = {
78	  items: { type: string; cursed?: boolean; enchantment?: number }[];
79	  isLoyalCustomer: boolean;
80	  isFollowUpContract: boolean;
81	};
82	
83	const computeStepPremium = (context: PremiumContext): number => {
84	  const basePremium = computeBasePremium(context.items);
85	  const itemSurcharges = computeItemSurcharges(context.items);
86	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
87	  const loyaltyDiscount = context.isLoyalCustomer
88	    ? basePremium * LOYALTY_DISCOUNT_RATE
89	    : 0;
90	  const followUpDiscount = context.isFollowUpContract
91	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
92	    : 0;
93	  return (
94	    basePremium +
95	    itemSurcharges +
96	    firstInsuranceSurcharge -
97	    loyaltyDiscount -
98	    followUpDiscount +
99	    PROCESSING_FEE
100	  );
101	};
102	
103	const INSURANCE_VALUES: Record<string, number> = {
104	  sword: 1000,
105	  amulet: 600,
106	  staff: 800,
107	  potion: 400,
108	  rune: 250,
109	  moonstone: 250,
110	};
111	
112	const DEDUCTIBLE_PER_DAMAGE = 100;
113	const CAP_MULTIPLIER = 2;
114	
115	type PolicyItem = { type: string; enchantment?: number };
116	
117	type PolicyState = {
118	  items: PolicyItem[];
119	  remainingCap: number;
120	};
121	
122	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
123	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
124	
125	const computeInsuranceSum = (items: { type: string }[]): number =>
126	  items.reduce((total, item) => total + (INSURANCE_VALUES[item.type] ?? 0), 0);
127	
128	const findPolicyItemOrThrow = (
129	  items: PolicyItem[],
130	  itemType: string,
131	): PolicyItem => {
132	  const item = items.find((i) => i.type === itemType);
133	  if (!item) {
134	    throw new Error(`Damaged item type not in policy: ${itemType}`);
135	  }
136	  return item;
137	};
138	
139	const assertNonNegativeDamage = (amount: number): void => {
140	  if (amount < 0) {
141	    throw new Error(`Damage amount cannot be negative: ${amount}`);
142	  }
143	};
144	
145	const computeDamagePayout = (
146	  damage: { itemType: string; amount: number },
147	  items: PolicyItem[],
148	): number => {
149	  assertNonNegativeDamage(damage.amount);
150	  const item = findPolicyItemOrThrow(items, damage.itemType);
151	  const reimbursable =
152	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
153	      ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
154	      : damage.amount;
155	  return reimbursable - DEDUCTIBLE_PER_DAMAGE;
156	};
157	
158	const computeClaimPayout = (
159	  damages: { itemType: string; amount: number }[],
160	  items: PolicyItem[],
161	): number =>
162	  damages.reduce((total, damage) => total + computeDamagePayout(damage, items), 0);
163	
164	type QuoteContext = {
165	  items: { type: string; cursed?: boolean; enchantment?: number }[];
166	  isLoyalCustomer: boolean;
167	  isFollowUpContract: boolean;
168	};
169	
170	const handleQuote = (
171	  step: any,
172	  index: number,
173	  policies: Record<number, PolicyState>,
174	  isLoyalCustomer: boolean,
175	): { premium: number } => {
176	  const items = step?.items ?? [];
177	  for (const item of items) {
178	    if (!isKnownItemType(item.type)) {
179	      throw new Error(`Unknown item type: ${item.type}`);
180	    }
181	  }
182	  policies[index] = {
183	    items,
184	    remainingCap: computeInsuranceSum(items) * CAP_MULTIPLIER,
185	  };
186	  const context: QuoteContext = {
187	    items,
188	    isLoyalCustomer,
189	    isFollowUpContract: index > 0,
190	  };
191	  return { premium: Math.ceil(computeStepPremium(context)) };
192	};
193	
194	const handleClaim = (
195	  step: any,
196	  policies: Record<number, PolicyState>,
197	): { payout: number; remainingCap: number } => {
198	  const policy = policies[step.policy];
199	  const damages = step?.incident?.damages ?? [];
200	  const desiredPayout = computeClaimPayout(damages, policy.items);
201	  const payout = Math.floor(Math.min(desiredPayout, policy.remainingCap));
202	  policy.remainingCap -= payout;
203	  return { payout, remainingCap: policy.remainingCap };
204	};
205	
206	export const runScenario = (scenario: any): unknown => {
207	  const steps = scenario?.steps ?? [];
208	  const isLoyalCustomer =
209	    (scenario?.customer?.yearsWithMHPCO ?? 0) >= LOYALTY_THRESHOLD_YEARS;
210	  const policies: Record<number, PolicyState> = {};
211	  const results = steps.map((step: any, index: number) =>
212	    step?.op === "claim"
213	      ? handleClaim(step, policies)
214	      : handleQuote(step, index, policies, isLoyalCustomer),
215	  );
216	  return { results };
217	};
